# Solution: Performance-Aware Error Handling

def lbyl_vs_eafp_key(data, key, default=None):
    """Use EAFP (try/except) to get a dict key with a default."""
    try:
        return data[key]
    except (KeyError, TypeError):
        return default

def batch_process(items, processor_func):
    """Process all items, collect results and errors.
    Return dict with "results" and "errors" lists."""
    results = []
    errors = []
    for i, item in enumerate(items):
        try:
            results.append(processor_func(item))
        except Exception as e:
            errors.append({"index": i, "item": item, "error": str(e)})
    return {"results": results, "errors": errors}

def error_rate(func, test_inputs):
    """Return float: count of errors / total inputs."""
    if not test_inputs:
        return 0.0
    error_count = 0
    for inp in test_inputs:
        try:
            func(inp)
        except Exception:
            error_count += 1
    return error_count / len(test_inputs)

def conditional_retry(func, should_retry_func, max_attempts=3):
    """Retry func() if should_retry_func(exception) returns True.
    Return result on success, raise last exception on failure."""
    last_exception = None
    for attempt in range(max_attempts):
        try:
            return func()
        except Exception as e:
            last_exception = e
            if not should_retry_func(e):
                raise
    raise last_exception

